INSERT INTO public.action_types (name, rpc_function, description, input_schema, output_schema, param_mapping, result_mapping, sensitive_fields, validation_rules, schema_version) VALUES ('add_project_member', 'add_project_member', 'Adds a user as a member of a project', '{"type": "object", "$schema": "http://json-schema.org/draft-07/schema#", "required": ["userId", "projectId"], "properties": {"userId": {"type": "string", "format": "uuid"}, "projectId": {"type": "string", "format": "uuid"}}, "additionalProperties": false}'::jsonb, '{"type": "object", "required": ["created"], "properties": {"created": {"type": "boolean"}}}'::jsonb, '{"userId": "p_from_id", "projectId": "p_to_id"}'::jsonb, '{"created": "created"}'::jsonb, ARRAY[]::text[], 'null'::jsonb, '1') ON CONFLICT (name) DO NOTHING;
INSERT INTO public.action_types (name, rpc_function, description, input_schema, output_schema, param_mapping, result_mapping, sensitive_fields, validation_rules, schema_version) VALUES ('add_user_repo', 'add_user_repo', 'Appends a repository to the user config repos array (idempotent)', '{"type": "object", "$schema": "http://json-schema.org/draft-07/schema#", "required": ["userResourceId", "owner", "name"], "properties": {"name": {"type": "string", "description": "Repository name"}, "owner": {"type": "string", "description": "Repository owner"}, "default": {"type": "boolean", "description": "Whether this is the default repo"}, "userResourceId": {"type": "string", "format": "uuid", "description": "UUID of the user resource"}}, "additionalProperties": false}'::jsonb, '{"type": "object", "properties": {"userResourceId": {"type": "string", "format": "uuid"}}}'::jsonb, '{"name": "p_name", "owner": "p_owner", "default": "p_default", "userResourceId": "p_user_resource_id"}'::jsonb, '{"user_resource_id": "userResourceId"}'::jsonb, ARRAY[]::text[], NULL, '1') ON CONFLICT (name) DO NOTHING;
INSERT INTO public.action_types (name, rpc_function, description, input_schema, output_schema, param_mapping, result_mapping, sensitive_fields, validation_rules, schema_version) VALUES ('assign_credential', 'assign_credential', 'Assigns a credential resource to an identity resource (max 1)', '{"type": "object", "$schema": "http://json-schema.org/draft-07/schema#", "required": ["resourceId", "credentialId"], "properties": {"resourceId": {"type": "string", "format": "uuid"}, "credentialId": {"type": "string", "format": "uuid"}}, "additionalProperties": false}'::jsonb, '{"type": "object", "required": ["created"], "properties": {"created": {"type": "boolean"}}}'::jsonb, '{"resourceId": "p_from_id", "credentialId": "p_to_id"}'::jsonb, '{"created": "created"}'::jsonb, ARRAY[]::text[], 'null'::jsonb, '1') ON CONFLICT (name) DO NOTHING;
INSERT INTO public.action_types (name, rpc_function, description, input_schema, output_schema, param_mapping, result_mapping, sensitive_fields, validation_rules, schema_version) VALUES ('assign_parent', 'assign_parent', 'Creates a parent link between two resources (identity→app, server→app, etc.)', '{"type": "object", "$schema": "http://json-schema.org/draft-07/schema#", "required": ["fromId", "toId"], "properties": {"toId": {"type": "string", "format": "uuid"}, "fromId": {"type": "string", "format": "uuid"}}, "additionalProperties": false}'::jsonb, '{"type": "object", "required": ["created"], "properties": {"created": {"type": "boolean"}}}'::jsonb, '{"toId": "p_to_id", "fromId": "p_from_id"}'::jsonb, '{"created": "created"}'::jsonb, ARRAY[]::text[], NULL, '1') ON CONFLICT (name) DO NOTHING;
INSERT INTO public.action_types (name, rpc_function, description, input_schema, output_schema, param_mapping, result_mapping, sensitive_fields, validation_rules, schema_version) VALUES ('assign_proxy', 'assign_proxy', 'Assigns a proxy resource to an identity resource (max 1)', '{"type": "object", "$schema": "http://json-schema.org/draft-07/schema#", "required": ["resourceId", "proxyId"], "properties": {"proxyId": {"type": "string", "format": "uuid"}, "resourceId": {"type": "string", "format": "uuid"}}, "additionalProperties": false}'::jsonb, '{"type": "object", "required": ["created"], "properties": {"created": {"type": "boolean"}}}'::jsonb, '{"proxyId": "p_to_id", "resourceId": "p_from_id"}'::jsonb, '{"created": "created"}'::jsonb, ARRAY[]::text[], 'null'::jsonb, '1') ON CONFLICT (name) DO NOTHING;
INSERT INTO public.action_types (name, rpc_function, description, input_schema, output_schema, param_mapping, result_mapping, sensitive_fields, validation_rules, schema_version) VALUES ('create_access_code', 'create_access_code', 'Creates a new access code for user onboarding. Auto-generates an 8-char hex code if none provided.', '{"type": "object", "$schema": "http://json-schema.org/draft-07/schema#", "properties": {"code": {"type": "string", "pattern": "^[A-Za-z0-9_-]{4,32}$"}, "config": {"type": "object"}}, "additionalProperties": false}'::jsonb, '{"type": "object", "required": ["accessCodeId", "code"], "properties": {"code": {"type": "string"}, "accessCodeId": {"type": "string"}}}'::jsonb, '{"code": "p_code", "config": "p_config"}'::jsonb, '{"code": "code", "access_code_id": "accessCodeId"}'::jsonb, ARRAY[]::text[], 'null'::jsonb, '1') ON CONFLICT (name) DO NOTHING;
INSERT INTO public.action_types (name, rpc_function, description, input_schema, output_schema, param_mapping, result_mapping, sensitive_fields, validation_rules, schema_version) VALUES ('create_agent', 'create_agent', 'Creates a new agent resource with property-system defaults, linked to a project', '{"type": "object", "$schema": "http://json-schema.org/draft-07/schema#", "required": ["name", "projectId"], "properties": {"name": {"type": "string"}, "config": {"type": "object"}, "projectId": {"type": "string", "format": "uuid"}}, "additionalProperties": false}'::jsonb, '{"type": "object", "required": ["agentResourceId"], "properties": {"agentResourceId": {"type": "string"}}}'::jsonb, '{"name": "p_name", "config": "p_config", "projectId": "p_project_id"}'::jsonb, '{"agent_resource_id": "agentResourceId"}'::jsonb, ARRAY[]::text[], 'null'::jsonb, '1') ON CONFLICT (name) DO NOTHING;
