INSERT INTO public.action_types (name, rpc_function, description, input_schema, output_schema, param_mapping, result_mapping, sensitive_fields, validation_rules, schema_version) VALUES ('create_credential', 'create_credential', 'Creates a new credential resource linked to a project', '{"type": "object", "$schema": "http://json-schema.org/draft-07/schema#", "required": ["name", "projectId", "dopplerProject"], "properties": {"name": {"type": "string"}, "config": {"type": "object"}, "projectId": {"type": "string", "format": "uuid"}, "dopplerProject": {"type": "string", "minLength": 1}}, "additionalProperties": false}'::jsonb, '{"type": "object", "required": ["credentialResourceId"], "properties": {"credentialResourceId": {"type": "string"}}}'::jsonb, '{"name": "p_name", "config": "p_config", "projectId": "p_project_id", "dopplerProject": "p_doppler_project"}'::jsonb, '{"credential_resource_id": "credentialResourceId"}'::jsonb, ARRAY[]::text[], 'null'::jsonb, '1') ON CONFLICT (name) DO NOTHING;
