INSERT INTO public.action_types (name, rpc_function, description, input_schema, output_schema, param_mapping, result_mapping, sensitive_fields, validation_rules, schema_version) VALUES ('create_project', 'create_project', 'Creates a new project resource, or returns the existing one if the name is already taken', '{"type": "object", "$schema": "http://json-schema.org/draft-07/schema#", "required": ["name"], "properties": {"name": {"type": "string", "minLength": 1}}, "additionalProperties": false}'::jsonb, '{"type": "object", "required": ["projectResourceId"], "properties": {"projectResourceId": {"type": "string"}}}'::jsonb, '{"name": "p_name"}'::jsonb, '{"project_resource_id": "projectResourceId"}'::jsonb, ARRAY[]::text[], '{"uniqueness": [{"error": "A project with this name already exists", "field": "name", "table": "resources", "where": {"type": "project"}, "input_field": "name", "on_conflict": "return_existing", "result_mapping": {"id": "projectResourceId"}}]}'::jsonb, '1') ON CONFLICT (name) DO NOTHING;
INSERT INTO public.action_types (name, rpc_function, description, input_schema, output_schema, param_mapping, result_mapping, sensitive_fields, validation_rules, schema_version) VALUES ('create_proxy', 'create_proxy', 'Creates a new proxy resource with property-system validation, linked to a project', '{"type": "object", "$schema": "http://json-schema.org/draft-07/schema#", "required": ["name", "projectId"], "properties": {"name": {"type": "string"}, "config": {"type": "object"}, "projectId": {"type": "string", "format": "uuid"}}, "additionalProperties": false}'::jsonb, '{"type": "object", "required": ["proxyResourceId"], "properties": {"proxyResourceId": {"type": "string"}}}'::jsonb, '{"name": "p_name", "config": "p_config", "projectId": "p_project_id"}'::jsonb, '{"proxy_resource_id": "proxyResourceId"}'::jsonb, ARRAY[]::text[], 'null'::jsonb, '1') ON CONFLICT (name) DO NOTHING;
