INSERT INTO public.action_types (name, rpc_function, description, input_schema, output_schema, param_mapping, result_mapping, sensitive_fields, validation_rules, schema_version) VALUES ('init_process', 'init_process', 'Creates a new process row in pending status and writes an audit action_event entry', '{"type": "object", "$schema": "http://json-schema.org/draft-07/schema#", "required": ["name"], "properties": {"name": {"type": "string", "minLength": 1}, "branch": {"type": "string"}, "runType": {"type": "string"}, "projectId": {"type": "string", "format": "uuid"}, "worktreePath": {"type": "string"}, "parentProcessId": {"type": "string", "format": "uuid"}, "skillResourceId": {"type": "string", "format": "uuid"}}, "additionalProperties": false}'::jsonb, '{"type": "object", "required": ["processId"], "properties": {"processId": {"type": "string"}}}'::jsonb, '{"name": "p_name", "branch": "p_branch", "runType": "p_run_type", "projectId": "p_project_id", "worktreePath": "p_worktree_path", "parentProcessId": "p_parent_process_id", "skillResourceId": "p_skill_resource_id"}'::jsonb, '{"process_id": "processId"}'::jsonb, ARRAY[]::text[], 'null'::jsonb, '1') ON CONFLICT (name) DO NOTHING;
INSERT INTO public.action_types (name, rpc_function, description, input_schema, output_schema, param_mapping, result_mapping, sensitive_fields, validation_rules, schema_version) VALUES ('provision_sandbox', 'provision_sandbox', 'Provisions a new sandbox server resource with idempotent ON CONFLICT handling', '{"type": "object", "$schema": "http://json-schema.org/draft-07/schema#", "required": ["userResourceId", "serverName", "sshKeyName", "publicKey"], "properties": {"publicKey": {"type": "string"}, "serverName": {"type": "string"}, "sshKeyName": {"type": "string"}, "userResourceId": {"type": "string", "description": "UUID of the user resource"}}, "additionalProperties": false}'::jsonb, '{"type": "object", "$schema": "http://json-schema.org/draft-07/schema#", "required": ["serverResourceId", "credentialResourceId", "isNew"], "properties": {"isNew": {"type": "boolean"}, "serverResourceId": {"type": "string"}, "credentialResourceId": {"type": "string"}}}'::jsonb, '{"publicKey": "p_public_key", "serverName": "p_server_name", "sshKeyName": "p_ssh_key_name", "userResourceId": "p_user_resource_id"}'::jsonb, '{"is_new": "isNew", "server_resource_id": "serverResourceId", "credential_resource_id": "credentialResourceId"}'::jsonb, ARRAY[]::text[], NULL, '1') ON CONFLICT (name) DO NOTHING;
INSERT INTO public.action_types (name, rpc_function, description, input_schema, output_schema, param_mapping, result_mapping, sensitive_fields, validation_rules, schema_version) VALUES ('provision_user', 'provision_user', 'Provisions a new user resource and default project in the ontology', '{"type": "object", "$schema": "http://json-schema.org/draft-07/schema#", "required": ["authUserId", "email"], "properties": {"email": {"type": "string", "format": "email"}, "authUserId": {"type": "string", "description": "UUID of the auth user"}}, "additionalProperties": false}'::jsonb, '{"type": "object", "$schema": "http://json-schema.org/draft-07/schema#", "required": ["userResourceId", "projectResourceId"], "properties": {"userResourceId": {"type": "string"}, "projectResourceId": {"type": "string"}}}'::jsonb, '{"email": "p_email", "authUserId": "p_auth_user_id"}'::jsonb, '{"user_resource_id": "userResourceId", "project_resource_id": "projectResourceId"}'::jsonb, ARRAY[]::text[], NULL, '1') ON CONFLICT (name) DO NOTHING;
INSERT INTO public.action_types (name, rpc_function, description, input_schema, output_schema, param_mapping, result_mapping, sensitive_fields, validation_rules, schema_version) VALUES ('redeem_access_code', 'redeem_access_code', 'Redeems an active access code: flips status to used, links user via redeemed_by. Fails if code is invalid or already used.', '{"type": "object", "$schema": "http://json-schema.org/draft-07/schema#", "required": ["code", "userId"], "properties": {"code": {"type": "string", "minLength": 1}, "userId": {"type": "string", "format": "uuid"}}, "additionalProperties": false}'::jsonb, '{"type": "object", "required": ["accessCodeId", "redeemed"], "properties": {"redeemed": {"type": "boolean"}, "accessCodeId": {"type": "string"}}}'::jsonb, '{"code": "p_code", "userId": "p_user_id"}'::jsonb, '{"redeemed": "redeemed", "access_code_id": "accessCodeId"}'::jsonb, ARRAY[]::text[], 'null'::jsonb, '1') ON CONFLICT (name) DO NOTHING;
INSERT INTO public.action_types (name, rpc_function, description, input_schema, output_schema, param_mapping, result_mapping, sensitive_fields, validation_rules, schema_version) VALUES ('remove_github_installation', 'remove_github_installation', 'Disconnects GitHub App by removing the resource_links row and credential resource. Does not revoke installation on GitHub.', '{"type": "object", "$schema": "http://json-schema.org/draft-07/schema#", "required": ["userResourceId"], "properties": {"userResourceId": {"type": "string", "format": "uuid", "description": "UUID of the user resource"}}, "additionalProperties": false}'::jsonb, '{"type": "object", "properties": {}}'::jsonb, '{"userResourceId": "p_user_resource_id"}'::jsonb, '{}'::jsonb, ARRAY[]::text[], NULL, '1') ON CONFLICT (name) DO NOTHING;
INSERT INTO public.action_types (name, rpc_function, description, input_schema, output_schema, param_mapping, result_mapping, sensitive_fields, validation_rules, schema_version) VALUES ('remove_user_repo', 'remove_user_repo', 'Removes a repository from the user config repos array', '{"type": "object", "$schema": "http://json-schema.org/draft-07/schema#", "required": ["userResourceId", "owner", "name"], "properties": {"name": {"type": "string", "description": "Repository name"}, "owner": {"type": "string", "description": "Repository owner"}, "userResourceId": {"type": "string", "format": "uuid", "description": "UUID of the user resource"}}, "additionalProperties": false}'::jsonb, '{"type": "object", "properties": {"userResourceId": {"type": "string", "format": "uuid"}}}'::jsonb, '{"name": "p_name", "owner": "p_owner", "userResourceId": "p_user_resource_id"}'::jsonb, '{"user_resource_id": "userResourceId"}'::jsonb, ARRAY[]::text[], NULL, '1') ON CONFLICT (name) DO NOTHING;
INSERT INTO public.action_types (name, rpc_function, description, input_schema, output_schema, param_mapping, result_mapping, sensitive_fields, validation_rules, schema_version) VALUES ('rename_project', 'rename_project', 'Renames an existing project resource; fails if the new name is already in use by another project', '{"type": "object", "$schema": "http://json-schema.org/draft-07/schema#", "required": ["projectResourceId", "newName"], "properties": {"newName": {"type": "string", "minLength": 1}, "projectResourceId": {"type": "string"}}, "additionalProperties": false}'::jsonb, '{"type": "object", "required": ["projectResourceId"], "properties": {"projectResourceId": {"type": "string"}}}'::jsonb, '{"newName": "p_new_name", "projectResourceId": "p_project_resource_id"}'::jsonb, '{"project_resource_id": "projectResourceId"}'::jsonb, ARRAY[]::text[], '{"uniqueness": [{"error": "A project with this name already exists", "field": "name", "table": "resources", "where": {"type": "project"}, "input_field": "newName", "on_conflict": "error"}]}'::jsonb, '1') ON CONFLICT (name) DO NOTHING;
INSERT INTO public.action_types (name, rpc_function, description, input_schema, output_schema, param_mapping, result_mapping, sensitive_fields, validation_rules, schema_version) VALUES ('rename_resource', 'rename_resource', 'Renames any resource by UUID. Rejects user and access-code types. Validates name against ^[a-zA-Z0-9/_-]{1,128}$.', '{"type": "object", "$schema": "http://json-schema.org/draft-07/schema#", "required": ["resourceId", "newName"], "properties": {"newName": {"type": "string", "pattern": "^[a-zA-Z0-9/_-]{1,128}$"}, "resourceId": {"type": "string", "format": "uuid"}}, "additionalProperties": false}'::jsonb, '{"type": "object", "required": ["resourceId", "oldName"], "properties": {"oldName": {"type": "string"}, "resourceId": {"type": "string"}}}'::jsonb, '{"newName": "p_new_name", "resourceId": "p_resource_id"}'::jsonb, '{"old_name": "oldName", "resource_id": "resourceId"}'::jsonb, ARRAY[]::text[], 'null'::jsonb, '1') ON CONFLICT (name) DO NOTHING;
INSERT INTO public.action_types (name, rpc_function, description, input_schema, output_schema, param_mapping, result_mapping, sensitive_fields, validation_rules, schema_version) VALUES ('store_github_installation', 'store_github_installation', 'Creates a credential resource for a GitHub App installation and links it to the user', '{"type": "object", "$schema": "http://json-schema.org/draft-07/schema#", "required": ["userResourceId", "installationId"], "properties": {"token": {"type": "string", "description": "Optional GitHub access token to vault"}, "provider": {"type": "string", "description": "Provider name (default: github)"}, "sandboxName": {"type": "string", "description": "Sandbox name for scoping"}, "installationId": {"type": "string", "description": "GitHub App installation ID"}, "userResourceId": {"type": "string", "format": "uuid", "description": "UUID of the user resource"}}, "additionalProperties": false}'::jsonb, '{"type": "object", "properties": {"credentialResourceId": {"type": "string", "format": "uuid"}}}'::jsonb, '{"token": "p_token", "provider": "p_provider", "sandboxName": "p_sandbox_name", "installationId": "p_installation_id", "userResourceId": "p_user_resource_id"}'::jsonb, '{"credential_resource_id": "credentialResourceId"}'::jsonb, ARRAY[]::text[], NULL, '1') ON CONFLICT (name) DO NOTHING;
INSERT INTO public.action_types (name, rpc_function, description, input_schema, output_schema, param_mapping, result_mapping, sensitive_fields, validation_rules, schema_version) VALUES ('store_user_credential', 'store_user_credential', 'Encrypt and store a provider credential in Vault with auth.uid() ownership check', '{"type": "object", "$schema": "http://json-schema.org/draft-07/schema#", "required": ["userResourceId", "sandboxName", "provider", "credentialValue"], "properties": {"provider": {"type": "string"}, "sandboxName": {"type": "string"}, "userResourceId": {"type": "string", "format": "uuid"}, "credentialValue": {"type": "string"}}, "additionalProperties": false}'::jsonb, '{"type": "object", "$schema": "http://json-schema.org/draft-07/schema#", "required": ["credentialResourceId", "vaultSecretId"], "properties": {"vaultSecretId": {"type": "string", "format": "uuid"}, "credentialResourceId": {"type": "string", "format": "uuid"}}}'::jsonb, '{"provider": "p_provider", "sandboxName": "p_sandbox_name", "userResourceId": "p_user_resource_id", "credentialValue": "p_credential_value"}'::jsonb, '{"vault_secret_id": "vaultSecretId", "credential_resource_id": "credentialResourceId"}'::jsonb, ARRAY['credentialValue']::text[], NULL, '1') ON CONFLICT (name) DO NOTHING;
INSERT INTO public.action_types (name, rpc_function, description, input_schema, output_schema, param_mapping, result_mapping, sensitive_fields, validation_rules, schema_version) VALUES ('update_cron_schedule', 'update_cron_schedule', 'Updates schedule, enabled state, or prompt for an existing cron resource', '{"type": "object", "$schema": "http://json-schema.org/draft-07/schema#", "required": ["resourceId"], "properties": {"prompt": {"type": "string"}, "enabled": {"type": "boolean"}, "schedule": {"type": "string"}, "resourceId": {"type": "string", "format": "uuid"}}, "additionalProperties": false}'::jsonb, '{"type": "object", "required": ["resourceId"], "properties": {"resourceId": {"type": "string"}}}'::jsonb, '{"prompt": "p_prompt", "enabled": "p_enabled", "schedule": "p_schedule", "resourceId": "p_resource_id"}'::jsonb, '{"resource_id": "resourceId"}'::jsonb, ARRAY[]::text[], 'null'::jsonb, '1') ON CONFLICT (name) DO NOTHING;
INSERT INTO public.action_types (name, rpc_function, description, input_schema, output_schema, param_mapping, result_mapping, sensitive_fields, validation_rules, schema_version) VALUES ('update_resource_status', 'update_resource_status', 'Updates a resource status with optional optimistic concurrency check via expectedStatus', '{"type": "object", "$schema": "http://json-schema.org/draft-07/schema#", "required": ["resourceId", "newStatus"], "properties": {"newStatus": {"enum": ["active", "inactive", "banned", "expired", "error", "used"], "type": "string"}, "resourceId": {"type": "string", "format": "uuid"}, "expectedStatus": {"enum": ["active", "inactive", "banned", "expired", "error", "used"], "type": "string"}}, "additionalProperties": false}'::jsonb, '{"type": "object", "required": ["resourceId", "oldStatus"], "properties": {"oldStatus": {"type": "string"}, "resourceId": {"type": "string"}}}'::jsonb, '{"newStatus": "p_new_status", "resourceId": "p_resource_id", "expectedStatus": "p_expected_status"}'::jsonb, '{"old_status": "oldStatus", "resource_id": "resourceId"}'::jsonb, ARRAY[]::text[], 'null'::jsonb, '1') ON CONFLICT (name) DO NOTHING;
INSERT INTO public.action_types (name, rpc_function, description, input_schema, output_schema, param_mapping, result_mapping, sensitive_fields, validation_rules, schema_version) VALUES ('update_sandbox_status', 'update_sandbox_status', 'Updates sandbox server status with IP, hetzner server ID, and provisioned timestamp', '{"type": "object", "$schema": "http://json-schema.org/draft-07/schema#", "required": ["serverResourceId", "status", "ip", "hetznerServerId", "provisionedAt"], "properties": {"ip": {"type": "string"}, "status": {"type": "string"}, "provisionedAt": {"type": "string", "format": "date-time"}, "hetznerServerId": {"type": "string"}, "serverResourceId": {"type": "string", "description": "UUID of the server resource"}}, "additionalProperties": false}'::jsonb, '{"type": "object", "$schema": "http://json-schema.org/draft-07/schema#", "properties": {}}'::jsonb, '{"ip": "p_ip", "status": "p_status", "provisionedAt": "p_provisioned_at", "hetznerServerId": "p_hetzner_server_id", "serverResourceId": "p_server_resource_id"}'::jsonb, '{}'::jsonb, ARRAY[]::text[], NULL, '1') ON CONFLICT (name) DO NOTHING;
INSERT INTO public.action_types (name, rpc_function, description, input_schema, output_schema, param_mapping, result_mapping, sensitive_fields, validation_rules, schema_version) VALUES ('update_skill_config', 'update_skill_config', 'Merges the provided config into an existing skill resource config, with formula XOR metric validation on the merged result', '{"type": "object", "$schema": "http://json-schema.org/draft-07/schema#", "required": ["resourceId", "config"], "properties": {"config": {"type": "object"}, "resourceId": {"type": "string", "format": "uuid"}}, "additionalProperties": false}'::jsonb, '{"type": "object", "required": ["resourceId"], "properties": {"resourceId": {"type": "string"}}}'::jsonb, '{"config": "p_config", "resourceId": "p_resource_id"}'::jsonb, '{"resource_id": "resourceId"}'::jsonb, ARRAY[]::text[], 'null'::jsonb, '1') ON CONFLICT (name) DO NOTHING;
INSERT INTO public.action_types (name, rpc_function, description, input_schema, output_schema, param_mapping, result_mapping, sensitive_fields, validation_rules, schema_version) VALUES ('update_skill_content', 'update_skill_content', 'Updates the content field within a skill resource config; validates length and prohibited path patterns', '{"type": "object", "$schema": "http://json-schema.org/draft-07/schema#", "required": ["resourceId", "content"], "properties": {"content": {"type": "string", "minLength": 101}, "resourceId": {"type": "string", "format": "uuid"}}, "additionalProperties": false}'::jsonb, '{"type": "object", "required": ["resourceId"], "properties": {"resourceId": {"type": "string"}}}'::jsonb, '{"content": "p_content", "resourceId": "p_resource_id"}'::jsonb, '{"resource_id": "resourceId"}'::jsonb, ARRAY[]::text[], 'null'::jsonb, '1') ON CONFLICT (name) DO NOTHING;
INSERT INTO public.action_types (name, rpc_function, description, input_schema, output_schema, param_mapping, result_mapping, sensitive_fields, validation_rules, schema_version) VALUES ('upload_skill', 'upload_skill', 'Uploads a skill goal as a resource to the ontology and returns its resource ID', '{"type": "object", "$schema": "http://json-schema.org/draft-07/schema#", "required": ["content", "actorId"], "properties": {"actorId": {"type": "string", "format": "uuid"}, "content": {"type": "string"}}, "additionalProperties": false}'::jsonb, '{"type": "object", "$schema": "http://json-schema.org/draft-07/schema#", "required": ["resourceId"], "properties": {"resourceId": {"type": "string"}}}'::jsonb, '{"actorId": "p_actor_id", "content": "p_content"}'::jsonb, '{"resource_id": "resourceId"}'::jsonb, ARRAY[]::text[], NULL, '1') ON CONFLICT (name) DO NOTHING;
